import{_ as t,c as n,o,ag as s}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),a={name:"guide/architecture.md"};function r(d,e,i,c,l,p){return o(),n("div",null,e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="layer-structure" tabindex="-1">Layer Structure <a class="header-anchor" href="#layer-structure" aria-label="Permalink to &quot;Layer Structure&quot;">​</a></h2><p>Robota SDK follows a strict bottom-up layered assembly model. Each layer builds on the layer below.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-cli                ← TUI layer: Ink TUI, useInteractiveSession hook, permission prompts</span></span>
<span class="line"><span>agent-transport-http     ← HTTP transport: Hono-based REST adapter (Cloudflare Workers / Node.js / Lambda)</span></span>
<span class="line"><span>agent-transport-mcp      ← MCP transport: Model Context Protocol server adapter</span></span>
<span class="line"><span>agent-transport-ws       ← WebSocket transport: framework-agnostic real-time adapter</span></span>
<span class="line"><span>  ↓ (all four consume)</span></span>
<span class="line"><span>agent-sdk                ← Assembly layer: InteractiveSession, SystemCommandExecutor,</span></span>
<span class="line"><span>  │                          CommandRegistry, BuiltinCommandSource, SkillCommandSource,</span></span>
<span class="line"><span>  │                          config, context, session factory, query()</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-sessions    ← Session lifecycle: permissions, hooks, compaction, persistence</span></span>
<span class="line"><span>agent-tools       ← Tool infrastructure + 8 built-in CLI tools</span></span>
<span class="line"><span>agent-providers   ← AI provider implementations (Anthropic, OpenAI, Google)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-core        ← Foundation: Robota engine, abstractions, DI, events, plugins</span></span></code></pre></div><h2 id="package-roles" tabindex="-1">Package Roles <a class="header-anchor" href="#package-roles" aria-label="Permalink to &quot;Package Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Role</th><th>Layer</th></tr></thead><tbody><tr><td><strong>agent-core</strong></td><td>Robota engine, execution loop, provider abstraction, permissions, hooks, plugin system, model definitions (SSOT)</td><td>Foundation</td></tr><tr><td><strong>agent-tools</strong></td><td>ToolRegistry, FunctionTool, createZodFunctionTool, 8 built-in CLI tools</td><td>General</td></tr><tr><td><strong>agent-sessions</strong></td><td>Session class with permission enforcement, context tracking, compaction</td><td>General</td></tr><tr><td><strong>agent-providers</strong></td><td>AnthropicProvider, OpenAIProvider, GoogleProvider</td><td>General</td></tr><tr><td><strong>agent-sdk</strong></td><td>Assembly: InteractiveSession, SystemCommandExecutor, CommandRegistry, BuiltinCommandSource, SkillCommandSource, config loading, context discovery, query()</td><td>SDK-specific</td></tr><tr><td><strong>agent-cli</strong></td><td>Ink TUI: useInteractiveSession hook bridges SDK events → React state, permission prompts</td><td>Transport</td></tr><tr><td><strong>agent-transport-http</strong></td><td>Hono-based HTTP/REST adapter — exposes InteractiveSession over HTTP (Cloudflare Workers, Node.js, AWS Lambda)</td><td>Transport</td></tr><tr><td><strong>agent-transport-mcp</strong></td><td>Model Context Protocol adapter — exposes InteractiveSession as an MCP server for Claude and other MCP clients</td><td>Transport</td></tr><tr><td><strong>agent-transport-ws</strong></td><td>Framework-agnostic WebSocket adapter — exposes InteractiveSession over real-time connections (works with any WS library)</td><td>Transport</td></tr><tr><td><strong>agent-remote-client</strong></td><td>HTTP client for calling a remote Robota agent exposed via agent-transport-http</td><td>Client</td></tr></tbody></table><h2 id="dependency-flow" tabindex="-1">Dependency Flow <a class="header-anchor" href="#dependency-flow" aria-label="Permalink to &quot;Dependency Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-cli              ─→ agent-sdk ─→ agent-sessions ─→ agent-core</span></span>
<span class="line"><span>agent-transport-http   ─→ agent-sdk    ├─→ agent-tools ────────────→ agent-core</span></span>
<span class="line"><span>agent-transport-mcp    ─→ agent-sdk    ├─→ agent-provider-anthropic → agent-core</span></span>
<span class="line"><span>agent-transport-ws     ─→ agent-sdk    └─────────────────────────→ agent-core</span></span>
<span class="line"><span>agent-remote-client                    (HTTP client, no agent-sdk dependency)</span></span></code></pre></div><h2 id="data-flow-ihistoryentry" tabindex="-1">Data Flow: IHistoryEntry[] <a class="header-anchor" href="#data-flow-ihistoryentry" aria-label="Permalink to &quot;Data Flow: IHistoryEntry[]&quot;">​</a></h2><p><code>InteractiveSession</code> maintains history as <code>IHistoryEntry[]</code> — a universal timeline that includes both chat messages (user/assistant turns) and session events (tool calls, system events, status changes). This is the single source of truth for display and persistence.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input</span></span>
<span class="line"><span>  → InteractiveSession.submit()</span></span>
<span class="line"><span>  → history appended: IHistoryEntry (kind: &#39;chat&#39;, role: &#39;user&#39;)</span></span>
<span class="line"><span>  → Session.run()</span></span>
<span class="line"><span>  → AI provider receives filtered view (chat-only IHistoryEntry[])</span></span>
<span class="line"><span>  → streaming response → text_delta / tool_start / tool_end events</span></span>
<span class="line"><span>  → history appended: IHistoryEntry (kind: &#39;chat&#39;, role: &#39;assistant&#39;)</span></span>
<span class="line"><span>  → event entries appended: IHistoryEntry (kind: &#39;event&#39;, ...)</span></span>
<span class="line"><span>  → thinking / context_update events emitted</span></span>
<span class="line"><span>  → clients (CLI, HTTP, MCP, WS) update their state from events</span></span></code></pre></div><p>Key invariant: AI providers never receive event-kind entries. The session layer filters to chat-only entries before forwarding context to the provider. This keeps the provider interface clean while the full <code>IHistoryEntry[]</code> timeline remains available for UI rendering.</p><p>Rules:</p><ul><li>Dependencies are one-way. No cycles.</li><li><code>agent-core</code> has zero workspace dependencies (foundation).</li><li><code>agent-sessions</code> depends only on <code>agent-core</code> (generic — no tools or providers).</li><li>Assembly (wiring tools + provider + prompt) happens in <code>agent-sdk</code>.</li><li><code>InteractiveSession</code> (in <code>agent-sdk</code>) is the gateway for all transport adapters. There is no separate <code>IAgentGateway</code> interface — transports consume <code>InteractiveSession</code> directly.</li><li><code>agent-cli</code> and all <code>agent-transport-*</code> packages depend only on <code>agent-sdk</code>; they do not access <code>agent-sessions</code> or <code>agent-core</code> directly.</li><li><code>agent-remote-client</code> is a standalone HTTP client; it does not depend on <code>agent-sdk</code>.</li></ul><h2 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Where</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Facade</strong></td><td><code>Robota</code>, <code>Session</code>, <code>InteractiveSession</code></td><td>Single entry point hiding internal complexity</td></tr><tr><td><strong>Decorator</strong></td><td><code>PermissionEnforcer.wrapTools()</code></td><td>Wraps tools with permission checks</td></tr><tr><td><strong>Strategy</strong></td><td><code>IAIProvider</code>, <code>ISessionLogger</code></td><td>Swappable implementations</td></tr><tr><td><strong>Factory</strong></td><td><code>InteractiveSession</code>, <code>createZodFunctionTool()</code></td><td>Object creation</td></tr><tr><td><strong>Null Object</strong></td><td><code>SilentLogger</code>, <code>DefaultEventService</code></td><td>Safe no-op defaults</td></tr><tr><td><strong>Registry</strong></td><td><code>ToolRegistry</code>, <code>CommandRegistry</code></td><td>Central management of tools and commands</td></tr><tr><td><strong>Composition</strong></td><td><code>InteractiveSession</code> → <code>Session</code>; <code>Session</code> → sub-components</td><td>Delegation over inheritance</td></tr></tbody></table><h2 id="session-sub-components" tabindex="-1">Session Sub-Components <a class="header-anchor" href="#session-sub-components" aria-label="Permalink to &quot;Session Sub-Components&quot;">​</a></h2><p><code>Session</code> delegates to focused sub-components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>PermissionEnforcer</code></td><td>Tool wrapping, permission checks, hook execution, output truncation</td></tr><tr><td><code>ContextWindowTracker</code></td><td>Token usage tracking, auto-compact threshold</td></tr><tr><td><code>CompactionOrchestrator</code></td><td>Conversation summarization via LLM (PreCompact hook)</td></tr></tbody></table><h2 id="interactivesession" tabindex="-1">InteractiveSession <a class="header-anchor" href="#interactivesession" aria-label="Permalink to &quot;InteractiveSession&quot;">​</a></h2><p><code>InteractiveSession</code> (in <code>agent-sdk</code>) wraps <code>Session</code> via composition to provide an event-driven API suitable for any interactive client. It is the single gateway used by all transport adapters — CLI, HTTP, MCP, and WebSocket — with no additional gateway interface required.</p><p>Key responsibilities:</p><table tabindex="0"><thead><tr><th>Concern</th><th>Detail</th></tr></thead><tbody><tr><td><strong>submit / abort</strong></td><td><code>submit(input)</code> starts a run; <code>abort()</code> cancels the current run</td></tr><tr><td><strong>cancelQueue</strong></td><td>Cancels the pending queued prompt without aborting the in-flight run</td></tr><tr><td><strong>Prompt queue</strong></td><td>Queues a new prompt submitted while a run is in progress</td></tr><tr><td><strong>Event emission</strong></td><td>Emits typed events (<code>text_delta</code>, <code>tool_start</code>, <code>tool_end</code>, <code>thinking</code>, <code>context_update</code>, <code>error</code>) consumed by clients</td></tr><tr><td><strong>Universal history</strong></td><td>Maintains <code>IHistoryEntry[]</code> — unified timeline of chat messages and session events; <code>getFullHistory()</code> returns the complete list</td></tr><tr><td><strong>SystemCommandExecutor</strong></td><td>Embedded inside <code>InteractiveSession</code>. Intercepts built-in system commands (help, clear, compact, mode, model, etc.) before any LLM call</td></tr><tr><td><strong>CommandRegistry</strong></td><td>Aggregates <code>BuiltinCommandSource</code> and <code>SkillCommandSource</code> for slash-command discovery</td></tr></tbody></table><p>The CLI&#39;s <code>useInteractiveSession</code> hook subscribes to these events and translates them into React state via <code>TuiStateManager</code>. <code>InteractiveSession</code> itself has no React dependency.</p><h2 id="transport-layer" tabindex="-1">Transport Layer <a class="header-anchor" href="#transport-layer" aria-label="Permalink to &quot;Transport Layer&quot;">​</a></h2><p>The transport layer exposes <code>InteractiveSession</code> over various protocols. Each transport is a thin adapter that bridges the protocol to the session&#39;s <code>submit</code> / <code>abort</code> / event API.</p><table tabindex="0"><thead><tr><th>Package</th><th>Protocol</th><th>Runtime</th></tr></thead><tbody><tr><td><strong>agent-cli</strong></td><td>Terminal (stdin)</td><td>Node.js (Ink + React)</td></tr><tr><td><strong>agent-transport-http</strong></td><td>HTTP / REST</td><td>Cloudflare Workers, Node.js, AWS Lambda (Hono)</td></tr><tr><td><strong>agent-transport-mcp</strong></td><td>MCP</td><td>Node.js stdio / SSE (MCP SDK)</td></tr><tr><td><strong>agent-transport-ws</strong></td><td>WebSocket</td><td>Any WS library (framework-agnostic)</td></tr></tbody></table><p>All four packages import <code>InteractiveSession</code> from <code>agent-sdk</code>. None of them implement session logic — they only translate protocol messages into session calls and forward session events back to the caller.</p><p>All transport adapters implement the <code>ITransportAdapter</code> interface (defined in <code>agent-sdk/src/interactive/types.ts</code>), which provides a uniform lifecycle: <code>attach(session)</code> to bind a session, <code>start()</code> to begin serving, and <code>stop()</code> to shut down. Each transport package exports a factory function that returns an <code>ITransportAdapter</code> implementation.</p><p><code>agent-remote-client</code> is a companion HTTP client that allows a remote process to call an agent exposed via <code>agent-transport-http</code>. It has no dependency on <code>agent-sdk</code>.</p><h2 id="plugin-architecture" tabindex="-1">Plugin Architecture <a class="header-anchor" href="#plugin-architecture" aria-label="Permalink to &quot;Plugin Architecture&quot;">​</a></h2><p><code>agent-core</code> defines the <code>AbstractPlugin</code> base class. 9 plugin implementations are available as separate <code>@robota-sdk/agent-plugin-*</code> packages. <code>EventEmitterPlugin</code> is also built directly into <code>agent-core</code> so that consumers do not need an additional dependency for basic event emission.</p><p>Plugins integrate with the agent lifecycle via hooks: <code>beforeRun</code>, <code>afterRun</code>, <code>onError</code>, <code>onStreamChunk</code>, <code>beforeToolExecution</code>, <code>afterToolExecution</code>.</p><h2 id="changes-from-v2-0-0" tabindex="-1">Changes from v2.0.0 <a class="header-anchor" href="#changes-from-v2-0-0" aria-label="Permalink to &quot;Changes from v2.0.0&quot;">​</a></h2><p>In v2.0.0, <code>agent-core</code> contained everything: tools, plugins, session management. In v3.0.0:</p><ul><li><strong>Tools</strong> moved to <code>agent-tools</code> (FunctionTool, ToolRegistry, built-in tools)</li><li><strong>Plugins</strong> extracted to <code>agent-plugin-*</code> packages</li><li><strong>Session</strong> created as a new package (<code>agent-sessions</code>) with permission and hook support</li><li><strong>SDK</strong> created as a new assembly layer (<code>agent-sdk</code>) with config/context loading</li><li><strong>CLI</strong> created as a new terminal UI (<code>agent-cli</code>)</li><li><strong>Permissions</strong> and <strong>Hooks</strong> added to <code>agent-core</code> as general-purpose infrastructure</li></ul>`,36)]))}const u=t(a,[["render",r]]);export{h as __pageData,u as default};
